import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

const secretKey = process.env.AUTH_SECRET_KEY || '';

export function middleware(req: NextRequest) {
  const token = req.cookies.get('authToken')?.value;

  if (!token) {
    return new NextResponse('Unauthorized', {
      status: 401,
      headers: { 'WWW-Authenticate': 'Bearer' },
    });
  }

  // Simple example of token verification (in a real-world scenario, you would verify the token with a JWT library)
  const isValidToken = token === secretKey;

  if (!isValidToken) {
    return new NextResponse('Unauthorized', {
      status: 401,
      headers: { 'WWW-Authenticate': 'Bearer' },
    });
  }

  // If the token is valid, continue to the next middleware or route handler
  return NextResponse.next();
}

export const config = {
  matcher: ['/api/:path*', '/protected/:path*'],
};